  ('fire-eq-tech-moex-02850', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '按「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」之規定，一般處理場所係指一日處理六 類物品數量達多少以上之場所：', '["數量達管制量以上之場所", "數量達管制量10倍以上之場所", "數量達管制量15倍以上之場所", "數量達管制量40倍以上之場所"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02851', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法」規定，地面樓層達多少以上建築物、地下建築物或中央主管機關指定之建築物，其管理權 有分屬時，各管理權人應協議製定共同消防防護計畫，並報請消防機關核備：', '["5層", "10層", "11層", "15層"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02852', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法施行細則」第20條規定設置之消防栓，下列敘述何者錯誤？', '["以採用地上單口式為原則，附近應設明顯標誌", "當地自來水事業負責保養、維護消防栓", "消防栓規格由中央主管機關定之", "縣（市）消防機關應定期會同當地自來水事業全面測試其性能，以保持堪用狀態"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02853', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「消防法」第27條之規定，直轄市、縣（市）政府，得聘請有關單位代表及學者專家，設火災鑑定 委員會調查、鑑定火災原因；其組織由何機關定之？', '["消防局", "直轄市、縣（市）政府", "消防署", "內政部"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02854', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依據「消防法施行細則」規定，下述何者不須遴用防火管理人並責成其製定消防防護計畫，報請消防機 關核備？', '["指壓按摩場所", "國際觀光旅館", "總樓地板面積為150平方公尺之補習班", "總樓地板面積為300平方公尺之餐廳"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02855', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法施行細則」規定，消防防護計畫有關滅火、通報及避難訓練之實施，應多久舉辦一次，每次 訓練不得少於多少小時？', '["半年，4小時", "半年，8小時", "一年，4小時", "一年，8小時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02856', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '消防法第11條中所稱「附有防焰標示之地毯、窗簾、布幕、展示用廣告板及其他指定之防焰物品」，不 包含下列何項物品？', '["人工草皮", "塑膠地板", "網目大小在12公釐以下之施工用帆布", "布質製窗簾"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02857', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「消防法施行細則」規定，管理權人依法檢查消防安全設備整體性之運作或使用，以判別其機能之方 式，屬於何種檢查？', '["運轉檢查", "外觀檢查", "性能檢查", "綜合檢查"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02858', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」規定，有關擋牆之設置規定何者錯誤？', '["設置位置距離場所外牆或相當於該外牆之設施外側2公尺以上", "不得超過該場所應保留空地寬度之五分之一，其未達2公尺者，以2公尺計", "厚度在10公分以上之鋼筋或鋼骨混凝土牆", "堆高斜度不超過60度之土堤"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02859', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '下列何者使用溫度在 40℃以下，以電弧或自動熔接之液化石油氣容器，不屬液化石油氣容器認可基準所 規範之液化石油氣容器？', '["2公斤裝液化石油氣容器", "10公斤裝液化石油氣容器", "50公斤裝液化石油氣容器", "100公斤裝液化石油氣容器"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "a64d4d092471", "answer_pdf_sha1": "465b7400ec13", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
